/**
 * Post-build script that injects a `scheduled` handler into the Cloudflare worker
 * generated by @sveltejs/adapter-cloudflare.
 *
 * The scheduled handler calls the /api/cron/sync endpoint every hour.
 */

import { readFileSync, writeFileSync } from 'fs';

const workerPath = '.svelte-kit/cloudflare/_worker.js';
let worker = readFileSync(workerPath, 'utf8');

if (worker.includes('scheduled')) {
	console.log('scheduled handler already present, skipping injection');
	process.exit(0);
}

// The adapter exports `worker_default` as the default export.
// We need to add a `scheduled` method to it.
const scheduledHandler = `

// --- Injected scheduled handler for hourly cron sync ---
const _originalDefault = worker_default;
const worker_with_scheduled = {
  ..._originalDefault,
  async scheduled(event, env, ctx) {
    const secret = env.CRON_SECRET;
    if (!secret) {
      console.error('CRON_SECRET not configured, skipping scheduled sync');
      return;
    }

    // We need to know our own origin. Use a synthetic request to the worker.
    const url = 'https://localhost/api/cron/sync';
    const request = new Request(url, {
      method: 'POST',
      headers: { 'x-cron-secret': secret }
    });

    ctx.waitUntil(
      _originalDefault.fetch(request, env, ctx)
        .then(res => res.json())
        .then(result => console.log('Cron sync complete:', JSON.stringify(result)))
        .catch(err => console.error('Cron sync failed:', err))
    );
  }
};
export { worker_with_scheduled as default };
`;

// Remove the existing default export and append our wrapper
worker = worker.replace(
	/export\s*\{\s*worker_default\s+as\s+default\s*\}\s*;?\s*$/,
	scheduledHandler
);

writeFileSync(workerPath, worker);
console.log('Injected scheduled handler into worker');
